function iconMarkup(tok, sz){ sz = sz||13; if(!tok){ tok='bolt'; }
  if(tok.indexOf('img:')===0){ const m={sperm:PUNTER_SPERM_IMG}; return '<img src="'+(m[tok.slice(4)]||'')+'" style="width:'+sz+'px;height:'+sz+'px;object-fit:contain;vertical-align:-2px"/>'; }
  const p=PUNTER_ICON_PATHS[tok]||PUNTER_ICON_PATHS.bolt; return '<svg viewBox="0 0 24 24" style="width:'+sz+'px;height:'+sz+'px;fill:none;stroke:currentColor;stroke-width:2;vertical-align:-2px">'+p+'</svg>'; }
function catIconTok(cat, c){ if(c && c.catIcon) return c.catIcon; const arr=PUNTER_CAT_ICONS[cat]||['bolt']; return arr[0]; }
function aoBadge(c){ if((c.cat||'active')!=='ao') return ''; return '<span style="display:inline-flex;align-items:center;gap:4px;font-family:var(--hd);font-weight:700;font-size:9px;padding:2px 7px;border-radius:4px;text-transform:uppercase;letter-spacing:.4px;background:var(--amber-bg);color:var(--amber);border:1px solid var(--amber-line)">'+iconMarkup(catIconTok('ao',c),11)+'AO</span>'; }

