  const chSel=c.channel||'auto'; const chRow=$('chanSeg'); if(chRow){ chRow.querySelectorAll('.seg').forEach(b=>b.classList.toggle('on', b.dataset.ch===chSel)); const eff=channelFor(c); $('chanWhy').textContent = c.channel ? 'override' : ((_ctry(c.number).c==='UK'?'UK':'non-UK')+' · '+(eff==='sms'?'SMS':'WhatsApp')+' by rule'); }
  go('s-detail');
