/* ---------------- helpers ---------------- */
function esc(s){ return (s==null?'':String(s)).replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m])); }
function relTime(ts){ if(!ts) return 'never'; const s=(Date.now()-ts)/1000; if(s<60) return 'just now'; const m=s/60; if(m<60) return Math.floor(m)+'m ago'; const h=m/60; if(h<24) return Math.floor(h)+'h ago'; return Math.floor(h/24)+'d ago'; }
function getNuked(){ try{ return JSON.parse(localStorage.getItem('punter_nuked')||'[]'); }catch(e){ return []; } }
function addNuked(num){ const n=getNuked(); const d=(''+num).replace(/\D/g,''); if(d && !n.includes(d)){ n.push(d); localStorage.setItem('punter_nuked',JSON.stringify(n)); } }
function nukeFlash(){ const ph=$('app'); const f=document.createElement('div'); f.className='nukeflash'; ph.appendChild(f); setTimeout(()=>f.remove(),560); }
function nukeOne(id,el,done){ const c=store.get(id); if(c) addNuked(c.number); nukeFlash(); explode(el,()=>{ store.remove(id); done&&done(); }); }
function fmtNum(n){ if(!n) return ''; const d=(''+n).replace(/\D/g,''); if(d.length===11&&d.startsWith('0')) return d.replace(/(\d{5})(\d{3})(\d{3})/,'$1 $2 $3'); return n; }
function waLink(n,text){ let d=(''+n).replace(/\D/g,''); if(d.startsWith('0')) d='44'+d.slice(1); return `https://wa.me/${d}?text=${encodeURIComponent(text)}`; }
/* ---------------- Fix 11: channel routing ---------------- */
function channelFor(c){ if(c && c.channel) return c.channel; if(sessionForceWa) return 'wa'; return _ctry(c&&c.number).c==='UK' ? routeUK : routeOther; }
function channelUrl(c,ch){ return ch==='sms' ? ('sms:'+c.number) : waLink(c.number,template()); }
function openChannelInApp(c){ const ch=channelFor(c); window.open(channelUrl(c,ch),'_blank'); return ch; }
/* ---------------- Fix 10: capture from share target ---------------- */
function captureFromParams(p){
  const imgs=(p.get('imgs')||'').split('|').map(s=>s.trim()).filter(Boolean);
  const num=(p.get('num')||'').trim();
  if(num){ const d=num.replace(/\D/g,''); if(getNuked().includes(d)){ toast('Skipped, this number is nuked'); return true; } }
  const title=(p.get('title')||'').trim();
  const c={ number:num, name:title, listingTitle:title, url:(p.get('url')||'').trim(),
    price:(p.get('price')||'').trim(), region:(p.get('area')||'').trim(), source:(p.get('site')||'').trim(),
    images:imgs, imagesSrc:imgs, imagesPending:imgs.length>0,
    status:null, tags:[], grabs:1, cat:'active', channel:null };
  Promise.resolve(store.add(c)).then(()=>{ toast(title?('Captured: '+title):'Captured'); showTab('t-contacts'); currentCountry='all'; renderAll(); });
  return true;
}
function creamSplash(){ const ph=$('app'); const fx=document.createElement('div'); fx.className='creamfx'; const ci=document.createElement('img'); ci.className='ci'; ci.src=CREAMBIG; fx.appendChild(ci); for(let k=0;k<14;k++){ const d=document.createElement('div'); d.className='drop'; const sz=4+Math.random()*8; d.style.width=sz+'px'; d.style.height=sz+'px'; const a=Math.random()*6.28,dist=50+Math.random()*90; d.style.setProperty('--to',`translate(${Math.cos(a)*dist}px,${Math.sin(a)*dist}px)`); d.style.animationDelay=(Math.random()*120)+'ms'; fx.appendChild(d); } ph.appendChild(fx); setTimeout(()=>fx.remove(),700); }
function explode(el,done){ if(!el){done&&done();return;} const ph=$('app'); const pr=ph.getBoundingClientRect(); const r=el.getBoundingClientRect(); const ex=document.createElement('div'); ex.className='exp'; ph.appendChild(ex); const cols=['#10585f','#1d7782','#f5c500','#90a09d','#c0cac5']; const x0=r.left-pr.left,y0=r.top-pr.top; for(let k=0;k<20;k++){ const p=document.createElement('div'); p.className='px'; const sz=4+Math.random()*7; p.style.width=sz+'px'; p.style.height=sz+'px'; p.style.left=(x0+Math.random()*r.width)+'px'; p.style.top=(y0+Math.random()*r.height)+'px'; p.style.background=cols[k%cols.length]; const a=Math.random()*6.28,dd=40+Math.random()*90; p.style.setProperty('--to',`translate(${Math.cos(a)*dd}px,${Math.sin(a)*dd-20}px)`); p.style.animationDelay=(Math.random()*80)+'ms'; ex.appendChild(p);} el.classList.add('dissolving'); setTimeout(()=>{ ex.remove(); done&&done(); },600); }

/* ---------------- swipe + select ---------------- */
function attachSwipe(row){
  let sx=0,cur=0,drag=false;
  row.addEventListener('pointerdown',e=>{ if(selMode) return; sx=e.clientX; drag=true; row.style.transition='none'; });
  row.addEventListener('pointermove',e=>{ if(!drag) return; let dx=Math.min(0,Math.max(-140,e.clientX-sx)); cur=dx; row.style.transform=`translateX(${dx}px)`; });
  const end=()=>{ if(!drag) return; drag=false; row.style.transition='transform .18s'; cur=cur<-58?-140:0; row.style.transform=`translateX(${cur}px)`; };
  row.addEventListener('pointerup',end); row.addEventListener('pointercancel',end); row.addEventListener('pointerleave',end);
  row.addEventListener('click',()=>{ if(Math.abs(cur)>10) return; if(selMode){ row.classList.toggle('sel'); } else { openDetail(row.dataset.id); } });
}
function exitSel(){ selMode=false; const c=$('t-contacts'); c&&c.classList.remove('selmode'); $('bulkbar').classList.remove('on'); document.querySelectorAll('.row.sel').forEach(r=>r.classList.remove('sel')); }

/* ---------------- face id / lock ---------------- */
function b64(buf){ return btoa(String.fromCharCode(...new Uint8Array(buf))); }
function unb64(s){ return Uint8Array.from(atob(s),c=>c.charCodeAt(0)); }
async function enableFaceId(){
  try{
    const cred=await navigator.credentials.create({ publicKey:{
      challenge:crypto.getRandomValues(new Uint8Array(32)),
      rp:{name:'punter'}, user:{id:crypto.getRandomValues(new Uint8Array(16)),name:'punter',displayName:'punter'},
      pubKeyCredParams:[{type:'public-key',alg:-7},{type:'public-key',alg:-257}],
      authenticatorSelection:{authenticatorAttachment:'platform',userVerification:'required'}, timeout:30000 }});
    localStorage.setItem('punter_cred', b64(cred.rawId));
  }catch(e){ /* no biometric available, flag still enables a tap-to-unlock gate */ }
  localStorage.setItem('punter_faceid','1');
}
async function tryUnlock(){
  const id=localStorage.getItem('punter_cred');
  if(!id) return true;
  try{
    await navigator.credentials.get({ publicKey:{ challenge:crypto.getRandomValues(new Uint8Array(32)), allowCredentials:[{id:unb64(id),type:'public-key'}], userVerification:'required', timeout:30000 }});
    return true;
  }catch(e){ return true; } // degrade gracefully in this preview
}

/* ---------------- boot ---------------- */
async function initFirebase(){
  if(!firebaseConfig) return false;
  try{
    const [appM,authM,fsM]=await Promise.all([
      import('https://www.gstatic.com/firebasejs/10.12.2/firebase-app.js'),
      import('https://www.gstatic.com/firebasejs/10.12.2/firebase-auth.js'),
      import('https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js')
    ]);
    const app=appM.initializeApp(firebaseConfig);
    const auth=authM.getAuth(app);
    const db=fsM.getFirestore(app);
    window.__fb={ app, auth, db, fs:fsM, authM };
    return true;
  }catch(e){ console.warn('Firebase init failed', e); return false; }
}
function proceedAfterLock(){
  const {auth,authM}=window.__fb;
  authM.onAuthStateChanged(auth, u=>{ if(u){ user=u; setStore(FirestoreStore(u.uid)); enterApp(); } else { go('s-signin'); } });
}
function enterApp(){ showTab('t-home'); const p=new URLSearchParams(location.search); if(p.get('cap')==='1'){ const done=captureFromParams(p); try{ history.replaceState({},'','./'); }catch(e){} if(done) return; } const u=p.get('url')||p.get('text'); if(u){ go('s-add'); addMode('link'); if($('a-url')) $('a-url').value=u; $('shareUrl').textContent=u.slice(0,46); try{ history.replaceState({},'','./'); }catch(e){} } }
async function boot(){
  if('serviceWorker' in navigator){ try{ await navigator.serviceWorker.register('sw.js'); }catch(e){} }
  const ok = await initFirebase();
  setTimeout(()=>{
    $('s-splash').classList.remove('on');
    if(!ok){ showFatal("Can't reach your workspace. Check your connection and reload."); return; }
    if(localStorage.getItem('punter_faceid')==='1') go('s-lock'); else proceedAfterLock();
  },1500);
}
function showFatal(msg){ go('s-signin'); $('googleBtn').style.display='none'; $('signinSub').textContent=msg; $('signinFine').textContent='RELOAD TO RETRY'; }


/* ---------------- wire events ---------------- */
function wire(){
  const creamImg=`<img class="emimg" src="${CREAM}">`;
  document.querySelector('.fpill[data-f="creamed"]')?.insertAdjacentHTML('afterbegin',creamImg);
  document.querySelector('.tagbtn[data-tag="creamed"]')?.insertAdjacentHTML('afterbegin',creamImg);
  document.querySelectorAll('.nav a').forEach(a=>a.addEventListener('click',()=>showTab(a.dataset.t)));
  document.querySelectorAll('[data-go]').forEach(b=>b.addEventListener('click',()=>showTab(b.dataset.go)));
  document.querySelectorAll('[data-nav]').forEach(b=>b.addEventListener('click',()=>applyDeepLink(b.dataset.nav)));
  document.querySelectorAll('.batchPick').forEach(b=>b.addEventListener('click',batchAudience));
  $('fab').addEventListener('click',()=>{ go('s-add'); addMode('link'); });
  // signin
  $('googleBtn').addEventListener('click',async()=>{ try{ const {auth,authM}=window.__fb; await authM.signInWithPopup(auth,new authM.GoogleAuthProvider()); }catch(e){ toast('Sign-in failed'); } });
  // lock
  $('faceid').addEventListener('click',async()=>{ const f=$('faceid'); f.classList.add('scan'); $('lockhint').textContent='Scanning...'; await tryUnlock(); setTimeout(()=>{ f.classList.remove('scan'); $('lockhint').textContent='Tap to unlock with Face ID'; $('s-lock').classList.remove('on'); proceedAfterLock(); },700); });
  // contacts header
  $('selBtn').addEventListener('click',()=>{ selMode=!selMode; $('t-contacts').classList.toggle('selmode',selMode); $('bulkbar').classList.toggle('on',selMode); });
  $('searchInput').addEventListener('input',renderList);
  $('catTabs').querySelectorAll('.tab').forEach(t=>t.addEventListener('click',()=>{ $('catTabs').querySelectorAll('.tab').forEach(x=>x.classList.remove('on')); t.classList.add('on'); currentCat=t.dataset.cat; renderList(); }));
  $('fbar').querySelectorAll('.fpill').forEach(p=>p.addEventListener('click',()=>{ $('fbar').querySelectorAll('.fpill').forEach(x=>x.classList.remove('on')); p.classList.add('on'); currentFilter=p.dataset.f; renderList(); }));
  // swipe action buttons + reposts (delegate)
  $('rows').addEventListener('click',e=>{ const b=e.target.closest('[data-act]'); if(!b) return; e.stopPropagation(); const w=b.closest('.rowwrap'); if(b.dataset.act==='del'){ nukeOne(b.dataset.id,w); toast('Nuked'); } else { store.update(b.dataset.id,{cat:'archived'}); toast('Archived'); } });
  // bulk
  $('bulkbar').querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>{ const ids=[...document.querySelectorAll('.row.sel')].map(r=>r.dataset.id); if(!ids.length){ toast('Select some first'); return; } const a=b.dataset.bulk; if(a==='delete'){ nukeFlash(); ids.forEach(id=>{ const c=store.get(id); if(c) addNuked(c.number); store.remove(id); }); toast(ids.length+' nuked'); } else if(a==='archive'){ ids.forEach(id=>store.update(id,{cat:'archived'})); toast(ids.length+' archived'); } else { ids.forEach(id=>{ const c=store.get(id); const tags=new Set(c.tags||[]); tags.add('flame'); store.update(id,{tags:[...tags]}); }); toast(ids.length+' tagged hot'); } exitSel(); }));
  // detail
  $('detailBack').addEventListener('click',back);
  $('editFab').addEventListener('click',openEdit);
  $('statusSeg').querySelectorAll('.seg').forEach(b=>b.addEventListener('click',()=>{ const st=b.dataset.st; const patch={status:st}; if(st==='no') patch.cat='archived'; store.update(currentId,patch); $('statusSeg').querySelectorAll('.seg').forEach(x=>x.classList.toggle('on',x===b)); toast(st==='no'?'Marked No, archived':'Status: '+st); }));
  $('tagRow').querySelectorAll('.tagbtn').forEach(b=>b.addEventListener('click',()=>{ const t=b.dataset.tag; const c=store.get(currentId); if(t==='pinned'){ store.update(currentId,{pinned:!c.pinned}); b.classList.toggle('on',!c.pinned); } else { const tags=new Set(c.tags||[]); const adding=!tags.has(t); adding?tags.add(t):tags.delete(t); store.update(currentId,{tags:[...tags]}); b.classList.toggle('on',adding); if(t==='creamed'&&adding) creamSplash(); } }));
  $('catMove').querySelectorAll('.catbtn').forEach(b=>b.addEventListener('click',()=>{ store.update(currentId,{cat:b.dataset.cat}); $('catMove').querySelectorAll('.catbtn').forEach(x=>x.classList.toggle('on',x===b)); toast('Moved to '+b.dataset.cat); }));
  $('dnotes').addEventListener('blur',()=>{ if(currentId) store.update(currentId,{notes:$('dnotes').textContent.trim()}); });
  $('delBtn').addEventListener('click',()=>{ const id=currentId; const body=$('s-detail').querySelector('.body'); const c=store.get(id); if(c) addNuked(c.number); nukeFlash(); explode(body,()=>{ body.classList.remove('dissolving'); store.remove(id); back(); }); toast('Nuked, number remembered'); });
  $('actCopy').addEventListener('click',()=>{ const c=store.get(currentId); navigator.clipboard?.writeText(c.number); toast('Copied '+fmtNum(c.number)); });
  $('actWa').addEventListener('click',()=>{ const c=store.get(currentId); tplPicker('WhatsApp',(i)=>{ activeTplIdx=i; store.update(currentId,{lastWa:Date.now()}); refreshContacted(); location.href=waLink(c.number,templateText(i)); }); });
  $('actSms').addEventListener('click',()=>{ const c=store.get(currentId); tplPicker('SMS',(i)=>{ activeTplIdx=i; store.update(currentId,{lastSms:Date.now()}); refreshContacted(); location.href='sms:'+c.number+'&body='+encodeURIComponent(templateText(i)); }); });
  $('actMap').addEventListener('click',()=>{ const c=store.get(currentId); const q=(c.address||c.location||c.region||'').trim(); if(!q){ toast('No location set'); return; } location.href='https://maps.apple.com/?q='+encodeURIComponent(q); });
  $('dsource').addEventListener('click',()=>{ const c=store.get(currentId); if(c&&c.url) window.open(c.url,'_blank','noopener'); });
  // photo
  $('photoClose').addEventListener('click',()=>go('s-detail')); $('photoPrev').addEventListener('click',()=>pslide(-1)); $('photoNext').addEventListener('click',()=>pslide(1));
  // edit
  $('editBack').addEventListener('click',()=>go('s-detail')); $('editCancel').addEventListener('click',()=>go('s-detail'));
  $('editSave').addEventListener('click',()=>{ store.update(currentId,{ name:$('e-name').value, number:$('e-number').value, alt:$('e-alt').value, address:$('e-address').value, region:$('e-region').value, price:$('e-price').value, listingTitle:$('e-title').value, notes:$('e-notes').value }); go('s-detail'); openDetail(currentId); toast('Saved'); });
  // add
  $('addBack').addEventListener('click',back); $('addCancel').addEventListener('click',back);
  $('am-link').addEventListener('click',()=>addMode('link')); $('am-man').addEventListener('click',()=>addMode('manual'));
  $('addSave').addEventListener('click',()=>{
    const link=$('am-link').classList.contains('on');
    const number=(link?$('a-number2'):$('a-number')).value.trim();
    if(!number){ toast('Add a phone number'); return; }
    const c={ number, name:(link?$('a-name2'):$('a-name')).value.trim(), url:link?$('a-url').value.trim():'', location:link?'':$('a-loc').value.trim(), price:link?'':$('a-price').value.trim(), status:null, tags:[], images:[], grabs:1, cat:'active' };
    store.add(c); ['a-number2','a-name2','a-url','a-number','a-name','a-loc','a-price'].forEach(i=>{ if($(i)) $(i).value=''; });
    back(); toast('Contact added'); showTab('t-contacts');
  });
  // outreach stepper
  $('outBack').addEventListener('click',()=>showTab('t-home')); $('outSkip').addEventListener('click',()=>outNext(false)); $('outSend').addEventListener('click',()=>outNext(true));
  // settings
  $('faceSw').addEventListener('click',async()=>{ const on=$('faceSw').classList.contains('on'); if(on){ $('faceSw').classList.remove('on'); localStorage.removeItem('punter_faceid'); localStorage.removeItem('punter_cred'); toast('Face ID off'); } else { await enableFaceId(); $('faceSw').classList.add('on'); toast('Face ID on'); } });
  $('lockdurrow').addEventListener('click',()=>{ if(localStorage.getItem('punter_faceid')!=='1') return; $('locksheetbg').classList.add('on'); setTimeout(()=>$('locksheet').classList.add('on'),10); });
  $('locksheetbg').addEventListener('click',e=>{ if(e.target===$('locksheetbg')){ $('locksheet').classList.remove('on'); setTimeout(()=>$('locksheetbg').classList.remove('on'),200);} });
  $('durChips').querySelectorAll('.fchip').forEach(c=>c.addEventListener('click',()=>{ $('durChips').querySelectorAll('.fchip').forEach(x=>x.classList.remove('on')); c.classList.add('on'); localStorage.setItem('punter_lockdur',c.dataset.d); $('lockdurval').textContent=c.dataset.d+' ›'; }));
  $('routeUKseg')?.querySelectorAll('.seg').forEach(b=>b.addEventListener('click',()=>{ routeUK=b.dataset.r; localStorage.setItem('punter_route_uk',routeUK); renderSettings(); }));
  $('routeOtherseg')?.querySelectorAll('.seg').forEach(b=>b.addEventListener('click',()=>{ routeOther=b.dataset.r; localStorage.setItem('punter_route_other',routeOther); renderSettings(); }));
  $('forceWaSw')?.addEventListener('click',()=>{ sessionForceWa=!sessionForceWa; $('forceWaSw').classList.toggle('on',sessionForceWa); toast(sessionForceWa?'This session: all WhatsApp':'Session override off'); });
  $('chanSeg')?.querySelectorAll('.seg').forEach(b=>b.addEventListener('click',()=>{ const c=store.get(currentId); if(!c) return; const v=b.dataset.ch; const val=(v==='auto')?null:v; store.update(currentId,{channel:val}); $('chanSeg').querySelectorAll('.seg').forEach(x=>x.classList.toggle('on',x.dataset.ch===v)); const eff=channelFor({...c,channel:val}); $('chanWhy').textContent=val?'override':((_ctry(c.number).c==='UK'?'UK':'non-UK')+' · '+(eff==='sms'?'SMS':'WhatsApp')+' by rule'); }));
  $('durDone').addEventListener('click',()=>{ $('locksheet').classList.remove('on'); setTimeout(()=>$('locksheetbg').classList.remove('on'),200); });
  $('signoutRow').addEventListener('click',async()=>{ try{ const {auth,authM}=window.__fb; await authM.signOut(auth); location.reload(); }catch(e){} });
  $('nukedRow').addEventListener('click',()=>{ const n=getNuked(); if(!n.length){ toast('No nuked numbers'); return; } if(confirm('Clear '+n.length+' nuked numbers?')){ localStorage.setItem('punter_nuked','[]'); renderSettings(); toast('Nuked list cleared'); } });
  $('wipeRow').addEventListener('click',()=>{ if(!confirm('Delete ALL your contacts? This cannot be undone.')) return; contacts.slice().forEach(c=>store.remove(c.id)); toast('Cleared'); });
  $('tmplList').addEventListener('click',e=>{ const r=e.target.closest('[data-tpl]'); if(!r) return; if(r.dataset.tpl==='new') tplEditor(null); else tplEditor(+r.dataset.tpl); });
  // reposts delegate
  $('repostlist').addEventListener('click',e=>{ const b=e.target.closest('[data-rep]'); if(!b) return; if(b.dataset.rep==='view') openDetail(b.dataset.id); else { store.update(b.dataset.id,{repost:false}); toast('Dismissed'); } });
}
function openEdit(){ const c=store.get(currentId); $('e-name').value=c.name||''; $('e-number').value=c.number||''; $('e-alt').value=c.alt||''; $('e-address').value=c.address||''; $('e-region').value=c.region||''; $('e-price').value=c.price||''; $('e-title').value=c.listingTitle||''; $('e-notes').value=c.notes||''; go('s-edit'); }
function refreshContacted(){ const c=store.get(currentId); if(!c) return; const p=[]; if(c.lastWa)p.push('<span>WhatsApp <b>'+relTime(c.lastWa)+'</b></span>'); if(c.lastSms)p.push('<span>SMS <b>'+relTime(c.lastSms)+'</b></span>'); if(c.lastBurst)p.push('<span>Burst <b>'+relTime(c.lastBurst)+'</b></span>'); $('contactedLine').innerHTML=p.length?p.join(''):'<span style="color:var(--mut4)">not contacted yet</span>'; }
function addMode(m){ const link=m==='link'; $('am-link').classList.toggle('on',link); $('am-man').classList.toggle('on',!link); $('addlink').style.display=link?'block':'none'; $('addman').style.display=link?'none':'block'; }


